body.script:
//
					const slides = document.querySelectorAll('.slide');
					const ind = document.getElementById('ind');
					let cur = 0;

					function show(i) {
						slides[cur].classList.remove('active');
						cur = ((i % slides.length) + slides.length) % slides.length;
						const slide = slides[cur];
						const iframe = slide.querySelector('iframe');
						if (!iframe.dataset.loaded) {
							iframe.src = slide.dataset.src;
							iframe.dataset.loaded = '1';
						}
						slide.classList.add('active');
						ind.textContent = slide.dataset.label;
					}

					show(0);

					document.addEventListener('keydown', e => {
						if (e.key === 'ArrowRight') show(cur + 1);
						else if (e.key === 'ArrowLeft') show(cur - 1);
					});

					let touchX = null;
					const overlay = document.getElementById('swipe-overlay');
					overlay.addEventListener('touchstart', e => {
						touchX = e.touches[0].clientX;
					}, { passive: true });
					overlay.addEventListener('touchend', e => {
						if (touchX === null) return;
						const dx = e.changedTouches[0].clientX - touchX;
						touchX = null;
						if (Math.abs(dx) < 40) return;
						show(dx < 0 ? cur + 1 : cur - 1);
					}, { passive: true });
				//

//
					const cfg              = document.getElementById('cfg').dataset;
					const INSTRUMENT       = cfg.instrument;
					const ASSET            = cfg.asset;
					const MONTHLY_INST     = cfg.monthly || '';
					const REFRESH          = parseInt(cfg.refresh, 10) * 1000;
					const ZONES_BOX_REFRESH = parseInt(cfg.zonesBoxRefresh, 10) * 1000;
					const ZONES_BOX_WINDOW_HOURS = parseInt(cfg.zonesBoxWindowHours, 10);
					const SHOW_DAILY_LINES   = cfg.showDaily !== 'false';
					const SHOW_WEEKLY_LINES  = cfg.showWeekly !== 'false';
					const SHOW_MONTHLY_LINES = cfg.showMonthly !== 'false';
					// Only true on /my/<asset> — /chart/<asset> always passes
					// show_gamma_point="false" (see _build_tv_chart_context).
					const SHOW_GAMMA_POINT = cfg.showGammaPoint === 'true';
					// /my/<asset> is the only minimal page (candles + gamma point
					// only — no Weekly/Monthly/All/Daily delta=0 lines, no zones
					// boxes/extrema), and currently the only one with the gamma
					// point, so this reuses that same flag rather than adding a
					// second backend-driven one; the footer (trade count/nearest
					// expiry) is untouched either way.
					const MINIMAL_CHART = SHOW_GAMMA_POINT;
					// User-toggleable via the "Lines" checkbox next to the Ruler
					// button (Delta Chart only — the Gamma Chart has no checkboxes
					// at all, see refreshGammaPointLines below) — hides every
					// horizontal price-line indicator (delta=0 sets) and, to
					// actually cut server load rather than just hiding the result
					// client-side, makes each of their refresh*() functions skip
					// the fetch entirely while off (see onToggleLines() below).
					// refreshMonthlyDeltaZero() is the one exception — it always
					// fetches regardless, since its trade_count feeds the footer.
					// Unchecked/off by default, matching the checkbox's own
					// default (unchecked) state above.
					let SHOW_ALL_LINES = false;
					// User-toggleable via the "Zones Extrema" checkbox (Delta Chart
					// only — this indicator is already suppressed on DG Chart via
					// MINIMAL_CHART, so this control isn't shown there at all, see the
					// t-if on its markup). Controls only the Top/Bottom Intersection +
					// Gamma Band lines (green/red/dashed violet) — deliberately NOT
					// the yellow/teal zones boxes, which stay always-on for now (a
					// separate show/hide control for those is planned but not added
					// yet). Stops refreshZonesExtrema()/refreshZonesExtremaExtended()
					// from calling the server at all while off — including the
					// expiry_index 1/2 background-refresh calls, so this page's own
					// live polling stops feeding those two expiries' rows in
					// dankbit.zones.extrema while off; expiry_index 0 (the nearest
					// expiry, via refreshZonesBoxes()) keeps persisting regardless,
					// since that endpoint isn't gated by this flag. The hourly
					// compute_snapshot() cron is untouched either way and keeps every
					// tracked expiry's row fresh on its own regardless of either flag.
					let SHOW_ZONES_EXTREMA = false;
					// Trade window used by the yellow/teal zones boxes (Delta Chart
					// only, radio toggle next to "Zones Extrema") — 'midnight' is the
					// original since-00:00-UTC-through-now default; 'hours' switches
					// to the trailing ZONES_BOX_WINDOW_HOURS hours instead (see
					// dankbit.zones_box_window_hours setting). Only 'hours' is ever
					// sent as a query param (see refreshZonesBoxes()) — like the
					// "Zones Extrema" checkbox, this is a live, non-persisted
					// override on the server side (see get_box()'s hours param); the
					// hourly compute_snapshot() cron and every other viewer's default
					// midnight-based view are completely unaffected either way.
					let ZONES_BOX_WINDOW_MODE = 'midnight';
					// "Nearest" / "Weekly" / "Monthly" checkboxes (Gamma Chart only)
					// — each toggles BOTH of that scope's line sets together (e.g.
					// "Nearest" hides/shows the black Nearest line AND the orange
					// Nearest 24h line as one unit — see refreshGammaPointLines'
					// gating below). "Nearest" is checked by default (so the chart
					// isn't empty on load); Weekly/Monthly default unchecked,
					// matching each checkbox's own default state — same
					// server-load-reducing pattern as "Lines"/"Zones Extrema" on
					// the Delta Chart: nothing is fetched until switched on.
					let GAMMA_SCOPE_NEAREST = true;
					let GAMMA_SCOPE_WEEKLY = false;
					let GAMMA_SCOPE_MONTHLY = false;
					const DZ_URL           = '/api/delta-zero/' + INSTRUMENT;
					const MDZ_URL          = MONTHLY_INST ? '/api/delta-zero/' + MONTHLY_INST : '';
					const ADZ_URL          = '/api/delta-zero-all/' + ASSET;
					const DZT_URL          = '/api/delta-zero-tomorrow/' + ASSET;
					const DZT2_URL         = '/api/delta-zero-day-after-tomorrow/' + ASSET;
					const GL_W_URL         = '/api/gamma-levels/' + INSTRUMENT;
					const GL_M_URL         = MONTHLY_INST ? '/api/gamma-levels/' + MONTHLY_INST : '';
					const ZE_URL           = '/api/zones-extrema/' + ASSET;
					const ZB_URL           = '/api/zones-box/' + ASSET;
					const NEAREST_EXPIRY_URL = '/api/nearest-expiry/' + ASSET;
					let   INTERVAL         = SHOW_GAMMA_POINT ? '1d' : '4h';
					const klineUrl   = (iv, limit) => '/api/klines/' + ASSET + '?interval=' + iv + '&limit=' + limit;

					// Lightweight Charts has no native IANA-timezone support — it always
					// renders epoch seconds as UTC wall-clock time. To display any other
					// zone, every timestamp fed into the chart is pre-shifted by that
					// zone's current UTC offset (DST-aware, since it's computed against
					// "now"), and localization.timeFormatter below formats with
					// timeZone: 'UTC' so the shifted epoch reads as real wall-clock time.
					// The zone itself is auto-detected from the browser rather than
					// hardcoded, falling back to UTC (offset 0) if detection ever fails.
					const tzOffset = (() => {
						let zone;
						try {
							zone = Intl.DateTimeFormat().resolvedOptions().timeZone;
						} catch (e) {
							return 0;
						}
						const d = new Date();
						const utc = new Date(d.toLocaleString('en-US', { timeZone: 'UTC' }));
						const local = new Date(d.toLocaleString('en-US', { timeZone: zone }));
						return (local - utc) / 1000;
					})();

					const chart = LightweightCharts.createChart(document.getElementById('chart-container'), {
						width: window.innerWidth, height: window.innerHeight,
						layout: { background: { type: 'solid', color: '#ffffff' }, textColor: '#333333' },
						grid: { vertLines: { color: '#e8e8e8' }, horzLines: { color: '#e8e8e8' } },
						crosshair: { mode: LightweightCharts.CrosshairMode.Normal, horzLine: { labelBackgroundColor: 'blue' } },
						rightPriceScale: { borderColor: '#cccccc' },
						timeScale: { borderColor: '#cccccc', timeVisible: true, secondsVisible: false },
						localization: {
							timeFormatter: ts => new Date(ts * 1000).toLocaleString('de-DE', {
								timeZone: 'UTC',
								month: 'short', day: 'numeric',
								hour: '2-digit', minute: '2-digit',
							}),
						},
					});

					window.addEventListener('resize', () => {
						chart.resize(window.innerWidth, window.innerHeight);
					});

					const series = chart.addCandlestickSeries({
						upColor: '#26a69a', downColor: '#ef5350',
						borderVisible: false, wickUpColor: '#26a69a', wickDownColor: '#ef5350',
					});

					// Invisible helper series solely to extend the shared time axis
					// FUTURE_MARGIN_DAYS past the last real candle, with labeled tick
					// marks. Candlestick setData() silently drops OHLC-less
					// "whitespace" points (confirmed empirically — a 30-point future
					// whitespace array passed alongside real candles left
					// series.data().length unchanged), so a real, fully-valued (if
					// invisible) line series is used instead; all series on a chart
					// share one time scale, so its future points extend the same axis
					// the candlesticks are drawn on.
					const futureAxisSeries = chart.addLineSeries({
						color: 'rgba(0,0,0,0)', lineWidth: 1,
						lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});

					const topIntersectionSeries    = chart.addLineSeries({ color: '#2e7d32', lineWidth: 2, lastValueVisible: false, priceLineVisible: false });
					const bottomIntersectionSeries = chart.addLineSeries({ color: '#c62828', lineWidth: 2, lastValueVisible: false, priceLineVisible: false });
					const gammaBandSeries          = chart.addLineSeries({ color: '#c9a0dc', lineWidth: 2, lineStyle: LightweightCharts.LineStyle.Dashed, lastValueVisible: false, priceLineVisible: false });

					// Zones boxes: filled rectangles marking the above-price and below-price
					// zero-crossing zones, using addBaselineSeries's flat top-line + baseValue
					// fill (the "line" is a constant top price, filled down to a constant
					// baseValue bottom price) to fake a bounded rectangle Lightweight Charts
					// has no native primitive for.
					const aboveBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#fbc02d', topFillColor1: 'rgba(251, 192, 45, 0.25)', topFillColor2: 'rgba(251, 192, 45, 0.25)',
						bottomLineColor: '#fbc02d', bottomFillColor1: 'rgba(251, 192, 45, 0.25)', bottomFillColor2: 'rgba(251, 192, 45, 0.25)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const belowBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#fbc02d', topFillColor1: 'rgba(251, 192, 45, 0.25)', topFillColor2: 'rgba(251, 192, 45, 0.25)',
						bottomLineColor: '#fbc02d', bottomFillColor1: 'rgba(251, 192, 45, 0.25)', bottomFillColor2: 'rgba(251, 192, 45, 0.25)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					// addBaselineSeries only strokes its top edge; add a plain line series
					// for the bottom edge so both edges get the same visible border.
					const aboveBoxBottomLine = chart.addLineSeries({ color: '#fbc02d', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });
					const belowBoxBottomLine = chart.addLineSeries({ color: '#fbc02d', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });

					// Short Max / Long Min box — same left/right time edges as the yellow
					// box above (both come from the same get_box() call for the nearest
					// expiry), teal so it stays visually distinct from yellow/violet/
					// green. setBoxData() already draws a single line instead of a box
					// when top and bottom coincide (or only one is available).
					const smlmBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: 'teal', topFillColor1: 'rgba(0, 128, 128, 0.25)', topFillColor2: 'rgba(0, 128, 128, 0.25)',
						bottomLineColor: 'teal', bottomFillColor1: 'rgba(0, 128, 128, 0.25)', bottomFillColor2: 'rgba(0, 128, 128, 0.25)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const smlmBoxBottomLine = chart.addLineSeries({ color: 'teal', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });

					// Gamma point lines (only on /my/<asset>, see SHOW_GAMMA_POINT) —
					// 6 line sets in 3 scopes, each scope toggled by its own
					// checkbox (GAMMA_SCOPE_NEAREST/WEEKLY/MONTHLY above, all
					// checked by default): Nearest/Weekly/Monthly (black, every
					// trade through expiry) plus Nearest 24h (orange)/Weekly 24h/
					// Monthly 24h (violet) — same expiry cutoff as their non-24h
					// counterparts, just restricted to the trailing 24h of trades
					// (gamma-levels' own ?hours= override, see gamma_levels_json).
					// All lineWidth 1, each drawing ALL gamma extrema via
					// drawGammaLines() (see its definition below) — reused here for
					// potentially-many peak/bottom lines instead of one averaged
					// point. Weekly/Monthly (both the every-trade and 24h variants)
					// use the same expiration >= NOW() AND expiration <= cutoff
					// query gamma_levels_json always has, so they already cover
					// every expiry up to and including that cutoff, not just the
					// single named instrument. Each refresh*() function skips its
					// own fetch entirely (not just hiding the result) while its
					// scope's checkbox is off, same server-load-reducing pattern
					// as "Lines"/"Zones Extrema" on the Delta Chart.
					async function refreshGammaPointNearest() {
						if (!SHOW_GAMMA_POINT || !GAMMA_SCOPE_NEAREST) {
							drawGammaLines({ peaks: [], bottoms: [] }, nearestGammaPointLines, 1, 'Nearest', 'black', 'black');
							return;
						}
						const nearest = await (await fetch(NEAREST_EXPIRY_URL)).json();
						if (!nearest.expiry) {
							drawGammaLines({ peaks: [], bottoms: [] }, nearestGammaPointLines, 1, 'Nearest', 'black', 'black');
							return;
						}
						const data = await (await fetch('/api/gamma-levels/' + nearest.expiry)).json();
						drawGammaLines(data, nearestGammaPointLines, 1, 'Nearest', 'black', 'black');
					}

					async function refreshGammaPointWeekly() {
						if (!SHOW_GAMMA_POINT || !GAMMA_SCOPE_WEEKLY) {
							drawGammaLines({ peaks: [], bottoms: [] }, weeklyGammaPointLines, 1, 'Weekly', 'black', 'black');
							return;
						}
						const data = await (await fetch(GL_W_URL)).json();
						drawGammaLines(data, weeklyGammaPointLines, 1, 'Weekly', 'black', 'black');
					}

					async function refreshGammaPointMonthly() {
						if (!SHOW_GAMMA_POINT || !GAMMA_SCOPE_MONTHLY || !GL_M_URL) {
							drawGammaLines({ peaks: [], bottoms: [] }, monthlyGammaPointLines, 1, 'Monthly', 'black', 'black');
							return;
						}
						const data = await (await fetch(GL_M_URL)).json();
						drawGammaLines(data, monthlyGammaPointLines, 1, 'Monthly', 'black', 'black');
					}

					// Orange "Nearest 24h" line — same nearest expiry as the black
					// Nearest line above, but restricted to the trailing 24h of
					// trades (gamma-levels' own ?hours= override, see
					// gamma_levels_json) rather than every trade through expiry.
					// Gated by the same GAMMA_SCOPE_NEAREST checkbox as the black
					// Nearest line, so one checkbox controls both.
					async function refreshGammaPointNearest24h() {
						if (!SHOW_GAMMA_POINT || !GAMMA_SCOPE_NEAREST) {
							drawGammaLines({ peaks: [], bottoms: [] }, nearest24hGammaPointLines, 1, 'Nearest 24h', 'orange', 'orange');
							return;
						}
						const nearest = await (await fetch(NEAREST_EXPIRY_URL)).json();
						if (!nearest.expiry) {
							drawGammaLines({ peaks: [], bottoms: [] }, nearest24hGammaPointLines, 1, 'Nearest 24h', 'orange', 'orange');
							return;
						}
						const data = await (await fetch('/api/gamma-levels/' + nearest.expiry + '?hours=24')).json();
						drawGammaLines(data, nearest24hGammaPointLines, 1, 'Nearest 24h', 'orange', 'orange');
					}

					// Violet "Weekly 24h" / "Monthly 24h" lines — same
					// every-expiry-up-to-and-including-cutoff scope as the black
					// Weekly/Monthly lines above (GL_W_URL/GL_M_URL), just
					// restricted to the trailing 24h of trades via the same
					// ?hours= override refreshGammaPointNearest24h uses. Gated by
					// the same GAMMA_SCOPE_WEEKLY/MONTHLY checkboxes as their
					// black counterparts.
					async function refreshGammaPointWeekly24h() {
						if (!SHOW_GAMMA_POINT || !GAMMA_SCOPE_WEEKLY) {
							drawGammaLines({ peaks: [], bottoms: [] }, weekly24hGammaPointLines, 1, 'Weekly 24h', 'violet', 'violet');
							return;
						}
						const data = await (await fetch(GL_W_URL + '?hours=24')).json();
						drawGammaLines(data, weekly24hGammaPointLines, 1, 'Weekly 24h', 'violet', 'violet');
					}

					async function refreshGammaPointMonthly24h() {
						if (!SHOW_GAMMA_POINT || !GAMMA_SCOPE_MONTHLY || !GL_M_URL) {
							drawGammaLines({ peaks: [], bottoms: [] }, monthly24hGammaPointLines, 1, 'Monthly 24h', 'violet', 'violet');
							return;
						}
						const data = await (await fetch(GL_M_URL + '?hours=24')).json();
						drawGammaLines(data, monthly24hGammaPointLines, 1, 'Monthly 24h', 'violet', 'violet');
					}

					async function refreshGammaPointLines() {
						if (!SHOW_GAMMA_POINT) return;
						await refreshGammaPointNearest();
						await refreshGammaPointWeekly();
						await refreshGammaPointMonthly();
						await refreshGammaPointNearest24h();
						await refreshGammaPointWeekly24h();
						await refreshGammaPointMonthly24h();
					}

					// "Nearest" / "Weekly" / "Monthly" checkboxes (Gamma Chart
					// only) — independent, not mutually exclusive: flips that
					// scope's flag and re-fetches (or clears, if just turned off)
					// only that scope's 2 line sets, leaving the other two scopes
					// untouched.
					function onToggleGammaScope(scope) {
						if (scope === 'nearest') {
							GAMMA_SCOPE_NEAREST = document.getElementById('nearest-expiry-toggle').checked;
							refreshGammaPointNearest();
							refreshGammaPointNearest24h();
						} else if (scope === 'weekly') {
							GAMMA_SCOPE_WEEKLY = document.getElementById('weekly-scope-toggle').checked;
							refreshGammaPointWeekly();
							refreshGammaPointWeekly24h();
						} else if (scope === 'monthly') {
							GAMMA_SCOPE_MONTHLY = document.getElementById('monthly-scope-toggle').checked;
							refreshGammaPointMonthly();
							refreshGammaPointMonthly24h();
						}
					}

					let priceLines    = [];
					let monthlyLines  = [];
					let allLines      = [];
					let tomorrowLines = [];
					let dayAfterTomorrowLines = [];

					function clearLines(arr) {
						arr.forEach(pl => series.removePriceLine(pl));
						arr.length = 0;
					}
					// Gamma Chart's own 3 gamma-extrema line sets (see
					// refreshGammaPointLines below) — the Delta Chart has no
					// gamma peak/bottom line indicator of its own any more
					// (removed; that indicator now lives only on the Gamma
					// Chart).
					let nearestGammaPointLines = [];
					let weeklyGammaPointLines = [];
					let monthlyGammaPointLines = [];
					let nearest24hGammaPointLines = [];
					let weekly24hGammaPointLines = [];
					let monthly24hGammaPointLines = [];

					function setStatus(text) { document.getElementById('status').textContent = text; }

					// "UTC Now:" clock (Delta Chart only — see #utc-now-label's t-if)
					// — plain wall-clock readout, no fetch involved, ticks every
					// second independent of any REFRESH poll.
					function updateUtcNowLabel() {
						const el = document.getElementById('utc-now-label');
						if (!el) return;
						el.textContent = new Date().toISOString().slice(11, 19);
					}

					function toCandle(k) {
						return { time: Math.floor(k.t / 1000) + tzOffset, open: parseFloat(k.o), high: parseFloat(k.h), low: parseFloat(k.l), close: parseFloat(k.c) };
					}

					const TF_WINDOW = { '1h': 30, '4h': 15, '1d': 365 };
					const BARS_PER_DAY = { '1h': 24, '4h': 6, '1d': 1 };
					const INTERVAL_SECONDS = { '1h': 3600, '4h': 4 * 3600, '1d': 86400 };

					const FUTURE_MARGIN_DAYS = 5;

					// realCandles.length + futureTickCount is the current total
					// logical bar count across both series sharing the time axis —
					// tracked directly rather than re-derived from series.data(),
					// since the candlestick series' own data() only ever reflects
					// realCandles (see futureAxisSeries above).
					let realCandles = [];
					let futureTickCount = 0;

					function applyVisibleRange() {
						const days = TF_WINDOW[INTERVAL] || 21;
						const barsPerDay = BARS_PER_DAY[INTERVAL] || 24;
						const lastIndex = realCandles.length + futureTickCount - 1;
						chart.timeScale().setVisibleLogicalRange({
							from: lastIndex - days * barsPerDay,
							to:   lastIndex,
						});
					}

					function rebuildSeriesData() {
						series.setData(realCandles);

						const intervalSec = INTERVAL_SECONDS[INTERVAL] || 3600;
						const lastClose = realCandles.length ? realCandles[realCandles.length - 1].close : 0;
						const lastTime = realCandles.length
							? realCandles[realCandles.length - 1].time
							: (Math.floor(Date.now() / 1000) + tzOffset);
						const count = Math.round(FUTURE_MARGIN_DAYS * 86400 / intervalSec);
						const futureTicks = [];
						for (let i = 1; i <= count; i++) {
							futureTicks.push({ time: lastTime + i * intervalSec, value: lastClose });
						}
						futureTickCount = futureTicks.length;
						futureAxisSeries.setData(futureTicks);
					}

					async function loadCandles() {
						const resp = await (await fetch(klineUrl(INTERVAL, 500))).json();
						const klines = (resp.result || []).slice().reverse();
						realCandles = klines.map(toCandle);
						rebuildSeriesData();
						applyVisibleRange();
					}

					async function updateLatestCandle() {
						const resp = await (await fetch(klineUrl(INTERVAL, 2))).json();
						const klines = resp.result || [];
						if (!klines.length) return;
						const updated = toCandle(klines[0]);
						if (realCandles.length && realCandles[realCandles.length - 1].time === updated.time) {
							realCandles[realCandles.length - 1] = updated;
						} else {
							realCandles.push(updated);
						}
						rebuildSeriesData();
					}

					async function setTf(iv) {
						INTERVAL = iv;
						document.querySelectorAll('.tf-btn').forEach(b => b.classList.toggle('active', b.textContent === iv));
						await loadCandles();
						await refreshZonesExtrema();
						await refreshZonesBoxes();
						await refreshZonesExtremaExtended();
					}

					async function refreshDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(DZ_URL)).json();
						clearLines(priceLines);
						if (!SHOW_WEEKLY_LINES) return;
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => priceLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'Weekly',
						})));
					}

					let nearestExpiryStr = null;
					let lastTradeCount = 0;

					function updateStatusLine() {
						const expiries = [INSTRUMENT, MONTHLY_INST].filter(Boolean).join('  ·  ');
						let text = expiries + '  ·  ' + lastTradeCount + ' trades';
						if (nearestExpiryStr) text += '  ·  Nearest: ' + nearestExpiryStr;
						setStatus(text);
					}

					async function refreshMonthlyDeltaZero() {
						if (!MDZ_URL) return;
						const data = await (await fetch(MDZ_URL)).json();
						clearLines(monthlyLines);
						// Line drawing is skipped in minimal mode or with the "Lines"
						// checkbox off, but this fetch still runs — its trade_count
						// feeds the footer's "N trades", which stays on /my/<asset> too.
						if (SHOW_MONTHLY_LINES && !MINIMAL_CHART && SHOW_ALL_LINES) {
							const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
							zeros.forEach(item => monthlyLines.push(series.createPriceLine({
								price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, axisLabelColor: 'black', title: 'Monthly',
							})));
						}
						lastTradeCount = data.trade_count || 0;
						updateStatusLine();
					}

					async function refreshNearestExpiry() {
						// Cheap standalone lookup (no curve-building) — the yellow zones
						// boxes use this same nearest-active-expiry internally, but via
						// their own full computation, not this lightweight endpoint.
						const data = await (await fetch(NEAREST_EXPIRY_URL)).json();
						nearestExpiryStr = data.expiry || null;
						updateStatusLine();
					}

					async function refreshAllDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(ADZ_URL)).json();
						clearLines(allLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => allLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'All',
						})));
					}

					async function refreshTomorrowDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(DZT_URL)).json();
						clearLines(tomorrowLines);
						if (!SHOW_DAILY_LINES) return;
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => tomorrowLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'orange', title: 'Daily (24H)',
						})));
					}

					async function refreshDayAfterTomorrowDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(DZT2_URL)).json();
						clearLines(dayAfterTomorrowLines);
						if (!SHOW_DAILY_LINES) return;
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => dayAfterTomorrowLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'orange', title: 'Daily+1 (24H)',
						})));
					}


					function drawGammaLines(data, lineStore, lineWidth, prefix, color = 'violet', axisLabelColor = 'black') {
						lineStore.forEach(l => series.removePriceLine(l));
						lineStore.length = 0;
						(data.peaks || []).forEach(item => {
							lineStore.push(series.createPriceLine({
								price: item.price, color, lineWidth,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, axisLabelColor,
								title: prefix + ' ∧ ' + (item.delta_positive ? 'Long Call' : 'Long Put'),
							}));
						});
						(data.bottoms || []).forEach(item => {
							lineStore.push(series.createPriceLine({
								price: item.price, color, lineWidth,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, axisLabelColor,
								title: prefix + ' ∨ ' + (item.delta_positive ? 'Short Put' : 'Short Call'),
							}));
						});
					}

					// "Lines" checkbox (next to Ruler) — hides every horizontal
					// price-line indicator (delta=0 sets) and stops their
					// refresh*() functions from even fetching (see SHOW_ALL_LINES
					// above), to actually cut server load rather than just hiding
					// the result. Turning off clears everything immediately rather
					// than waiting for each set's own next poll (their refresh*()
					// functions return before their own clearLines() call when
					// SHOW_ALL_LINES is false). Turning back on re-fetches
					// everything immediately for the same reason.
					// refreshMonthlyDeltaZero() is untouched here — it always
					// keeps polling regardless, for the footer's trade count.
					function onToggleLines() {
						SHOW_ALL_LINES = document.getElementById('lines-toggle').checked;
						if (SHOW_ALL_LINES) {
							refreshDeltaZero();
							refreshMonthlyDeltaZero();
							refreshAllDeltaZero();
							refreshTomorrowDeltaZero();
							refreshDayAfterTomorrowDeltaZero();
						} else {
							clearLines(priceLines);
							clearLines(monthlyLines);
							clearLines(allLines);
							clearLines(tomorrowLines);
							clearLines(dayAfterTomorrowLines);
						}
					}

					function clearZonesExtremaLines() {
						topIntersectionSeries.setData([]);
						bottomIntersectionSeries.setData([]);
						gammaBandSeries.setData([]);
						topIntersectionSeries.setMarkers([]);
						bottomIntersectionSeries.setMarkers([]);
					}

					async function refreshZonesExtrema() {
						if (MINIMAL_CHART || !SHOW_ZONES_EXTREMA) return;
						const data = await (await fetch(ZE_URL)).json();
						const rows = data.zones_extrema || [];
						topIntersectionSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.top_intersection })));
						bottomIntersectionSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.bottom_intersection })));
						gammaBandSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.gamma_band })));

						// +/- marker per point: whether the payoff at that
						// intersection (not the intersection's own price) sits
						// above or below the zero-payoff line — size:0 hides the
						// marker's shape glyph so only the text renders.
						topIntersectionSeries.setMarkers(rows.map(r => ({
							time: Math.floor(r.t / 1000) + tzOffset,
							position: 'aboveBar',
							color: '#2e7d32',
							shape: 'circle',
							size: 0,
							text: r.top_intersection_positive ? '+' : '-',
						})));
						bottomIntersectionSeries.setMarkers(rows.map(r => ({
							time: Math.floor(r.t / 1000) + tzOffset,
							position: 'aboveBar',
							color: '#c62828',
							shape: 'circle',
							size: 0,
							text: r.bottom_intersection_positive ? '+' : '-',
						})));
					}

					function setBoxData(boxSeries, bottomLineSeries, top, bottom, fromTime, toTime) {
						// 0.0 is the "no crossing at all" sentinel (see
						// dankbit.zones.extrema) — nothing real to draw on that edge.
						if (!top && !bottom) { boxSeries.setData([]); bottomLineSeries.setData([]); return; }
						if (top && bottom && top !== bottom) {
							boxSeries.applyOptions({ baseValue: { type: 'price', price: bottom } });
							boxSeries.setData([
								{ time: fromTime, value: top },
								{ time: toTime, value: top },
							]);
							bottomLineSeries.setData([
								{ time: fromTime, value: bottom },
								{ time: toTime, value: bottom },
							]);
							return;
						}
						// Only one edge has a crossing, or both coincide (zero-height
						// box) — can't draw a rectangle, so draw a single line at
						// whichever price we do have instead of dropping it silently.
						const price = top || bottom;
						boxSeries.setData([]);
						bottomLineSeries.setData([
							{ time: fromTime, value: price },
							{ time: toTime, value: price },
						]);
					}

					function clearZonesBoxes() {
						aboveBoxSeries.setData([]);
						belowBoxSeries.setData([]);
						aboveBoxBottomLine.setData([]);
						belowBoxBottomLine.setData([]);
						smlmBoxSeries.setData([]);
						smlmBoxBottomLine.setData([]);
					}

					async function refreshZonesBoxes() {
						if (MINIMAL_CHART) return;
						// Live lookup — computed fresh by the server on every call (see
						// dankbit.zones.extrema.get_box), not read from stored history.
						// Persisted (feeding the Zones Extrema lines' history) unless
						// ZONES_BOX_WINDOW_MODE is 'hours', in which case the ?hours=
						// override makes the server compute display-only instead — see
						// ZONES_BOX_WINDOW_MODE above.
						const url = ZONES_BOX_WINDOW_MODE === 'hours'
							? ZB_URL + '?hours=' + ZONES_BOX_WINDOW_HOURS
							: ZB_URL;
						const data = await (await fetch(url)).json();
						if (!data || data.t === undefined) {
							clearZonesBoxes();
							return;
						}
						const fromTime = Math.floor(Date.now() / 1000) + tzOffset - 10 * 86400;
						const toTime   = Math.floor(data.expiration / 1000) + tzOffset;

						const aboveTop    = Math.max(data.short_zero_above_price, data.long_zero_above_price);
						const aboveBottom = Math.min(data.short_zero_above_price, data.long_zero_above_price);
						setBoxData(aboveBoxSeries, aboveBoxBottomLine, aboveTop, aboveBottom, fromTime, toTime);

						const belowTop    = Math.max(data.short_zero_below_price, data.long_zero_below_price);
						const belowBottom = Math.min(data.short_zero_below_price, data.long_zero_below_price);
						setBoxData(belowBoxSeries, belowBoxBottomLine, belowTop, belowBottom, fromTime, toTime);

						// Short Max / Long Min box — same fromTime/toTime as the yellow box
						// above, since both come from this same nearest-expiry get_box() call.
						const smlmTop    = Math.max(data.short_max_price, data.long_min_price);
						const smlmBottom = Math.min(data.short_max_price, data.long_min_price);
						setBoxData(smlmBoxSeries, smlmBoxBottomLine, smlmTop, smlmBottom, fromTime, toTime);
					}

					async function refreshZonesExtremaExtended() {
						if (MINIMAL_CHART || !SHOW_ZONES_EXTREMA) return;
						// Only the nearest active expiry (expiry_index 0) draws a box —
						// expiry_index 1 through 2 just keep their dankbit.zones.extrema
						// rows fresh while the chart is open (see get_box_n), the same way
						// refreshZonesBoxes() does for 0, so refreshZonesExtrema()'s next
						// poll picks up fresher Top/Bottom Intersection and Gamma Band
						// points for them — no box is rendered from this call's
						// response, so there's nothing to do with it beyond triggering the
						// server-side computation.
						for (const i of [1, 2]) {
							try { await fetch('/api/zones-extrema-refresh/' + ASSET + '/' + i); } catch (e) { /* best-effort */ }
						}
					}

					// "Zones Extrema" checkbox (Delta Chart only, next to "Lines") —
					// controls only the Top/Bottom Intersection + Gamma Band lines
					// (green/red/dashed violet), NOT the yellow/teal zones boxes,
					// which have their own separate show/hide control (not added
					// yet — see refreshZonesBoxes(), left ungated by this flag on
					// purpose). Stops refreshZonesExtrema()/refreshZonesExtremaExtended()
					// from calling the server at all while off (see
					// SHOW_ZONES_EXTREMA above), not just hiding the result — the
					// cron is untouched, this only stops this browser's own
					// contribution to keeping dankbit.zones.extrema fresh. Clears
					// the lines immediately when switched off (refreshZonesExtrema()
					// returns before clearing when SHOW_ZONES_EXTREMA is false) and
					// re-fetches immediately when switched back on.
					function onToggleZonesExtrema() {
						SHOW_ZONES_EXTREMA = document.getElementById('zones-toggle').checked;
						if (SHOW_ZONES_EXTREMA) {
							refreshZonesExtrema();
							refreshZonesExtremaExtended();
						} else {
							clearZonesExtremaLines();
						}
					}

					// 00:00-UTC-vs-trailing-hours radio toggle for the zones boxes
					// (see ZONES_BOX_WINDOW_MODE above) — re-fetches immediately on
					// change rather than waiting for the next ZONES_BOX_REFRESH poll.
					function onZonesBoxWindowChange() {
						ZONES_BOX_WINDOW_MODE = document.getElementById('zones-box-window-hours').checked ? 'hours' : 'midnight';
						refreshZonesBoxes();
					}

					let rulerActive = false;
					let rulerPrice1 = null;
					let rulerLines  = [];

					function toggleRuler() {
						rulerActive = !rulerActive;
						document.getElementById('ruler-btn').classList.toggle('active', rulerActive);
						rulerLines.forEach(l => series.removePriceLine(l));
						rulerLines = [];
						rulerPrice1 = null;
						const info = document.getElementById('ruler-info');
						info.style.display = 'none';
						info.textContent = '';
					}

					chart.subscribeClick(param => {
						if (!rulerActive || !param.point) return;
						const price = series.coordinateToPrice(param.point.y);
						if (rulerPrice1 === null) {
							rulerPrice1 = price;
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, axisLabelColor: 'black', title: '①',
							}));
						} else {
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, axisLabelColor: 'black', title: '②',
							}));
							const pct = ((price - rulerPrice1) / rulerPrice1 * 100);
							const sign = pct >= 0 ? '+' : '';
							const info = document.getElementById('ruler-info');
							info.style.display = 'block';
							info.textContent = rulerPrice1.toFixed(0) + ' → ' + price.toFixed(0) + '   ' + sign + pct.toFixed(2) + '%';
							rulerPrice1 = null;
						}
					});

					async function init() {
						try { await loadCandles(); await refreshDeltaZero(); await refreshMonthlyDeltaZero(); await refreshAllDeltaZero(); await refreshTomorrowDeltaZero(); await refreshDayAfterTomorrowDeltaZero(); await refreshZonesExtrema(); await refreshZonesBoxes(); await refreshZonesExtremaExtended(); await refreshNearestExpiry(); await refreshGammaPointLines(); }
						catch (e) { setStatus('Error: ' + e.message); }
					}
					function saveChart() {
						const canvases = document.getElementById('chart-container').querySelectorAll('canvas');
						if (!canvases.length) return;
						const w = canvases[0].width, h = canvases[0].height;
						const out = document.createElement('canvas');
						out.width = w; out.height = h;
						const ctx = out.getContext('2d');
						ctx.fillStyle = '#ffffff';
						ctx.fillRect(0, 0, w, h);
						canvases.forEach(c => ctx.drawImage(c, 0, 0));
						const a = document.createElement('a');
						a.href = out.toDataURL('image/png');
						a.download = INSTRUMENT + '_delta_' + new Date().toISOString().slice(0,16).replace('T','_') + '.png';
						a.click();
					}

					updateUtcNowLabel();
					init();
					setInterval(updateLatestCandle, 5000);
					setInterval(updateUtcNowLabel, 1000);
					setInterval(refreshDeltaZero, REFRESH);
					setInterval(refreshMonthlyDeltaZero, REFRESH);
					setInterval(refreshNearestExpiry, REFRESH);
					setInterval(refreshAllDeltaZero, REFRESH);
					setInterval(refreshTomorrowDeltaZero, REFRESH);
					setInterval(refreshDayAfterTomorrowDeltaZero, REFRESH);
					setInterval(refreshZonesExtrema, REFRESH);
					setInterval(refreshZonesBoxes, ZONES_BOX_REFRESH);
					setInterval(refreshZonesExtremaExtended, REFRESH);
					setInterval(refreshGammaPointLines, REFRESH);
				//
